parameters.jsCode:
const outlineData = $input.first().json.outline || '';
const nlpTerms = JSON.parse($input.first().json.nlp_terms || '[]');
const lines = outlineData.split('\n');
const sections = [];
let currentSection = null;
let currentContent = [];
for (const line of lines) {
  if (line.startsWith('## ')) {
    if (currentSection) {
      sections.push({ sectionTitle: currentSection, sectionContent: currentContent.join('\n') });
    }
    currentSection = line.substring(3).trim();
    currentContent = [line];
  } else if (currentSection) {
    currentContent.push(line);
  }
}
if (currentSection) {
  sections.push({ sectionTitle: currentSection, sectionContent: currentContent.join('\n') });
}
const termsPerSection = Math.ceil(nlpTerms.length / Math.max(sections.length, 1));
return sections.map((s, i) => ({
  json: {
    ...s,
    assigned_nlp_terms: nlpTerms.slice(i * termsPerSection, (i + 1) * termsPerSection),
    brandGuidelines: $input.first().json.brandGuidelines || '',
    keyword: $input.first().json.keyword || '',
    paa_questions: $input.first().json.paa_questions || '[]',
    target_word_count: $input.first().json.target_word_count || 0
  }
}));

