const response = $input.first().json.output || $input.first().json.text || '';
let meta;
try { meta = JSON.parse(response); } catch(e) {
  const match = response.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (match) meta = JSON.parse(match[1]);
  else meta = { title: 'Untitled', meta_description: '', slug: 'untitled', key_takeaways: [] };
}
return [{ json: meta }];

const article = $input.first().json.html_content || '';
const nlpTermsRaw = $('Set Writer Context').item.json.nlp_terms || '[]';
const nlpTerms = typeof nlpTermsRaw === 'string' ? JSON.parse(nlpTermsRaw) : nlpTermsRaw;
const articleLower = article.toLowerCase();
let found = 0;
const missing = [];
for (const term of nlpTerms) {
  const t = typeof term === 'string' ? term : term.term || '';
  if (articleLower.includes(t.toLowerCase())) { found++; } else { missing.push(t); }
}
const score = nlpTerms.length > 0 ? Math.round((found / nlpTerms.length) * 100) : 0;
const wordCount = article.replace(/<[^>]+>/g, ' ').split(/\s+/).filter(w => w).length;
return [{ json: { ...$input.first().json, nlp_score: score, word_count: wordCount, missing_terms: missing } }];
